func (EtcdConnection) serverReachable(connURL *url.URL) bool {
        scheme := connURL.Scheme
        if scheme == "http" || scheme == "https" || scheme == "tcp" {
                scheme = "tcp"
        }
        if conn, err := net.DialTimeout(scheme, connURL.Host, connectionTimeout); err == nil {
                defer conn.Close()
                return true
        }
        return false
}

